<template><ion-page><AppHeader title="Recuperar Senha" back /><ion-content class="vivid-page"><div class="auth-page"><h1>Esqueci minha senha</h1><p>Informe seu e-mail para receber o link de recuperação.</p><AppField v-model="email" label="E-mail" placeholder="nome@empresa.com.br" :icon="mailOutline" /><button class="primary-button" @click="submit">Enviar link</button><p v-if="message" class="success">{{ message }}</p></div></ion-content></ion-page></template>
<script setup lang="ts">import { ref } from 'vue'; import { IonPage,IonContent,toastController } from '@ionic/vue'; import { mailOutline } from 'ionicons/icons'; import AppHeader from '@/components/AppHeader.vue'; import AppField from '@/components/AppField.vue'; import { useAuthStore } from '@/stores/auth'; const email=ref(''),message=ref(''),store=useAuthStore(); const submit=async()=>{try{message.value=(await store.requestPasswordReset(email.value)).message}catch{const t=await toastController.create({message:'Não foi possível enviar o link',color:'danger',duration:2500});t.present()}};</script>
<style scoped>.auth-page{padding:40px 22px;color:var(--vivid-text)}.auth-page p{color:var(--vivid-muted);margin-bottom:28px}.success{color:#a7e9b4!important}</style>
